/**
 * MedX card runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Builds KPI cards, inventory summaries, and alert surfaces for the dashboard grid.
 */
const CARD_VARIANTS = Object.freeze({
  default: { elevation: "shadow-sm", border: "border border-border" },
  elevated: { elevation: "shadow-lg", border: "border-0" },
  outline: { elevation: "shadow-none", border: "border-2 border-dashed border-muted" },
  destructive: { elevation: "shadow-md", border: "border border-destructive/50" },
  success: { elevation: "shadow-sm", border: "border border-emerald-500/30" },
});

const KPI_TEMPLATES = Object.freeze({
  totalInventory: {
    title: "Total Inventory Value",
    format: "currency",
    trendKey: "inventoryTrend",
  },
  activeOrders: {
    title: "Active Orders",
    format: "integer",
    trendKey: "ordersTrend",
  },
  coldChainAlerts: {
    title: "Cold Chain Alerts",
    format: "integer",
    variant: "destructive",
    trendKey: "alertsTrend",
  },
  complianceScore: {
    title: "Compliance Score",
    format: "percent",
    variant: "success",
    trendKey: "complianceTrend",
  },
});

const cardRegistry = new Map();
let cardIdCounter = 0;

function formatCardValue(value, format) {
  switch (format) {
    case "currency":
      return new Intl.NumberFormat("en-US", { style: "currency", currency: "USD" }).format(value);
    case "percent":
      return `${Number(value).toFixed(1)}%`;
    case "integer":
      return new Intl.NumberFormat("en-US").format(Math.round(value));
    default:
      return String(value);
  }
}

function createCard(config) {
  cardIdCounter += 1;
  const id = config.id ?? `medx-card-${cardIdCounter}`;
  const template = config.template ? KPI_TEMPLATES[config.template] : null;
  const variant = config.variant ?? template?.variant ?? "default";

  const card = {
    id,
    title: config.title ?? template?.title ?? "Card",
    subtitle: config.subtitle ?? null,
    value: config.value ?? 0,
    format: config.format ?? template?.format ?? "integer",
    variant,
    styles: CARD_VARIANTS[variant] ?? CARD_VARIANTS.default,
    trend: config.trend ?? null,
    footer: config.footer ?? null,
    actions: config.actions ?? [],
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
  };
  cardRegistry.set(id, card);
  return card;
}

function updateCardValue(id, value, trend) {
  const card = cardRegistry.get(id);
  if (!card) return null;
  card.value = value;
  if (trend !== undefined) card.trend = trend;
  card.updatedAt = Date.now();
  return {
    ...card,
    displayValue: formatCardValue(card.value, card.format),
  };
}

function renderCardSummary(id) {
  const card = cardRegistry.get(id);
  if (!card) return null;
  return {
    id: card.id,
    title: card.title,
    displayValue: formatCardValue(card.value, card.format),
    variant: card.variant,
    trend: card.trend,
    hasFooter: Boolean(card.footer),
    actionCount: card.actions.length,
  };
}

function buildDashboardCards(metrics) {
  return Object.entries(KPI_TEMPLATES).map(([key, template]) =>
    createCard({
      template: key,
      value: metrics[key] ?? 0,
      trend: metrics[template.trendKey] ?? null,
      footer: `Updated ${new Date().toISOString()}`,
    }),
  );
}

async function runMedxCard() {
  console.log("[medx:ui:card] runtime initialized");
  console.log(`[medx:ui:card] variants=${Object.keys(CARD_VARIANTS).length} templates=${Object.keys(KPI_TEMPLATES).length}`);

  const demoMetrics = {
    totalInventory: 2847593.42,
    inventoryTrend: { direction: "up", delta: 4.2 },
    activeOrders: 127,
    ordersTrend: { direction: "down", delta: -2.1 },
    coldChainAlerts: 3,
    alertsTrend: { direction: "up", delta: 1 },
    complianceScore: 96.8,
    complianceTrend: { direction: "up", delta: 0.5 },
  };

  const cards = buildDashboardCards(demoMetrics);
  updateCardValue(cards[0].id, 2900000, { direction: "up", delta: 5.1 });

  const summaries = Array.from(cardRegistry.values()).map((c) => renderCardSummary(c.id));
  console.log(`[medx:ui:card] registered=${cardRegistry.size}`);
  console.log("[medx:ui:card] summaries", summaries.map((s) => `${s.title}=${s.displayValue}`).join(" | "));
  console.log("[medx:ui:card] bootstrap complete");
}

module.exports = runMedxCard;
